class Solution {
    public String sortString(String s) {
        int[] count = new int[26];
        for (char c : s.toCharArray()) {
            count[c - 'a']++;
        }
        StringBuilder sb = new StringBuilder();
        while (s.length() > 0) {
            // append smallest characters
            for (int i = 0; i < 26; i++) {
                if (count[i] > 0) {
                    sb.append((char) ('a' + i));
                    count[i]--;
                    s = s.replaceFirst(String.valueOf((char) ('a' + i)), "");
                }
            }
            // append largest characters
            for (int i = 25; i >= 0; i--) {
                if (count[i] > 0) {
                    sb.append((char) ('a' + i));
                    count[i]--;
                    s = s.replaceFirst(String.valueOf((char) ('a' + i)), "");
                }
            }
        }
        return sb.toString();
    }
}
